diff --git a/app.parta.io/test_network.js b/app.parta.io/test_network.js
new file mode 100644
index 0000000..8717df1
--- /dev/null
+++ b/app.parta.io/test_network.js
@@ -0,0 +1,31 @@
+const http = require('http');
+const https = require('https');
+
+console.log("Testing outbound connection...");
+const req = https.get('https://google.com', (res) => {
+  console.log(`Outbound Success: Status Code ${res.statusCode}`);
+}).on('error', (e) => {
+  console.error(`Outbound Blocked/Failed: ${e.message}`);
+});
+req.setTimeout(5000, () => {
+    console.error("Outbound Timeout");
+    req.destroy();
+});
+
+console.log("Testing inbound connection...");
+const server = http.createServer((req, res) => {
+  res.writeHead(200);
+  res.end('Hello');
+});
+
+server.listen(0, '0.0.0.0', () => {
+  console.log(`Server listening on port ${server.address().port}`);
+  
+  const testReq = http.get(`http://localhost:${server.address().port}`, (res) => {
+     console.log(`Inbound Localhost Success: Status Code ${res.statusCode}`);
+     server.close();
+  }).on('error', (e) => {
+     console.error(`Inbound Localhost Failed: ${e.message}`);
+     server.close();
+  });
+});

